func (m *matchersTree) match(req *http.Request) bool {
	if m == nil {

		log.Warn().Msg("Rule matcher is nil")
		return false
	}

	if m.matcher != nil {
		return m.matcher(req)
	}

	switch m.operator {
	case "or":
		return m.left.match(req) || m.right.match(req)
	case "and":
		return m.left.match(req) && m.right.match(req)
	default:

		log.Warn().Str("operator", m.operator).Msg("Invalid rule operator")
		return false
	}
}
